import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"API Overview","description":"","frontmatter":{},"headers":[],"relativePath":"developer/api-overview.md","filePath":"developer/api-overview.md","lastUpdated":null}'),o={name:"developer/api-overview.md"};function i(n,t,s,h,c,l){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="api-overview" tabindex="-1">API Overview <a class="header-anchor" href="#api-overview" aria-label="Permalink to &quot;API Overview&quot;">​</a></h1><p>The API is served by <code>src/Autofac.Api</code>. The OpenAPI document is available at:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/openapi/v1.json</span></span></code></pre></div><h2 id="health-and-runtime" tabindex="-1">Health and runtime <a class="header-anchor" href="#health-and-runtime" aria-label="Permalink to &quot;Health and runtime&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET /api/health/live</code></td><td>Liveness probe.</td></tr><tr><td><code>GET /api/health/ready</code></td><td>Readiness probe with runtime information.</td></tr><tr><td><code>GET /api/health/runtime</code></td><td>Active workflow runtime mode.</td></tr><tr><td><code>GET /api/health/camunda</code></td><td>Camunda topology/status when that adapter is active.</td></tr></tbody></table><h2 id="auth" tabindex="-1">Auth <a class="header-anchor" href="#auth" aria-label="Permalink to &quot;Auth&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET /api/auth/config</code></td><td>Auth discovery/configuration.</td></tr><tr><td><code>POST /api/auth/token</code></td><td>Development token endpoint when enabled.</td></tr></tbody></table><p>Development token endpoints are not production authentication.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET /api/settings</code></td><td>Redacted Admin settings catalog.</td></tr><tr><td><code>PATCH /api/settings</code></td><td>Save supported non-secret values and rotate supported secrets.</td></tr><tr><td><code>POST /api/settings/tests/{target}</code></td><td>Run a dry-run readiness check.</td></tr></tbody></table><p>Settings requires Admin access.</p><h2 id="workflows-and-runs" tabindex="-1">Workflows and runs <a class="header-anchor" href="#workflows-and-runs" aria-label="Permalink to &quot;Workflows and runs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET /api/workflows</code></td><td>List workflows.</td></tr><tr><td><code>GET /api/workflows/{workflowId}</code></td><td>Read one workflow.</td></tr><tr><td><code>POST /api/runs</code></td><td>Start a run.</td></tr><tr><td><code>GET /api/runs</code></td><td>List runs.</td></tr><tr><td><code>GET /api/runs/{runId}</code></td><td>Read run detail.</td></tr></tbody></table><h2 id="approvals" tabindex="-1">Approvals <a class="header-anchor" href="#approvals" aria-label="Permalink to &quot;Approvals&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET /api/approvals</code></td><td>List approval requests.</td></tr><tr><td><code>POST /api/approvals/{approvalId}/decision</code></td><td>Approve, reject, or request changes.</td></tr></tbody></table><p>Approval decisions require the Approver role or a higher role with equivalent access.</p><h2 id="artifacts-and-evidence" tabindex="-1">Artifacts and evidence <a class="header-anchor" href="#artifacts-and-evidence" aria-label="Permalink to &quot;Artifacts and evidence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST /api/runs/{runId}/artifacts/{artifactName}</code></td><td>Upload artifact bytes.</td></tr><tr><td><code>GET /api/runs/{runId}/artifacts/{artifactName}</code></td><td>Download an artifact.</td></tr><tr><td><code>GET /api/runs/{runId}/evidence-pack</code></td><td>Generate evidence-pack JSON.</td></tr><tr><td><code>GET /api/runs/{runId}/evidence-pack/download</code></td><td>Download evidence-pack JSON.</td></tr></tbody></table><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST /webhooks/github</code></td><td>Receive signed GitHub events such as <code>issues</code>.</td></tr></tbody></table><p>GitHub webhooks are anonymous at the HTTP auth layer but validated through signature checking.</p><h2 id="api-usage-pattern" tabindex="-1">API usage pattern <a class="header-anchor" href="#api-usage-pattern" aria-label="Permalink to &quot;API usage pattern&quot;">​</a></h2><ol><li>Obtain a valid token for the target role.</li><li>Start or inspect a workflow run.</li><li>Follow pending approval or wait-state information.</li><li>Retrieve artifacts or evidence after completion.</li><li>Use audit and evidence data for investigation or records retention.</li></ol>',23)])])}const b=e(o,[["render",i]]);export{u as __pageData,b as default};
